// Base64-encoded brand logo bytes, generated from app/static/brands/*.
// Inlined as strings so branded emails can embed the logo as a data: URI with
// no runtime filesystem read (portable across adapter-node and adapter-vercel).

export interface LogoAsset {
	base64: string;
	mime: string;
}

export const BRAND_LOGO_ASSETS: Record<string, LogoAsset> = {
	"/brands/champion-infometrics.png": { base64: "", mime: "image/png" },
	"/brands/champion-infratech.png": { base64: "", mime: "image/png" },
	"/brands/champion-products.webp": { base64: "", mime: "image/webp" },
	"/brands/champions-club.png": { base64: "", mime: "image/png" },
	"/brands/champions-yacht-club.png": { base64: "", mime: "image/png" },
	"/brands/cirrologix.png": { base64: "", mime: "image/png" },
	"/brands/ip-momentum.png": { base64: "", mime: "image/png" },
};
